import{_ as a,c as l,g as e,o as n}from"./chunks/framework.CCxIPCIe.js";const m=JSON.parse('{"title":"四〇三","description":"","frontmatter":{"title":"四〇三","date":"2026-02-26T09:39:44.230Z","length":"815字","time":"3分钟","aside":false,"hash":-1101532103},"headers":[],"relativePath":"idea/403.md","filePath":"idea/403.md"}'),s={name:"idea/403.md"};function r(p,t,o,d,i,u){return n(),l("div",null,t[0]||(t[0]=[e("p",null,"学数学的人好像大多都有股反驳欲，接触多了很恼人，好像时时刻刻要在智性上压服你，所以要逃离。我也不懂，感觉老外学数学的就很好说话，有那种天赋又高又很包容的。感觉和数学没啥关系，主要是伪装成数学家的做题家，数学不过是做题家粘在肉里的长衫，抠都抠不下来。",-1),e("p",null,"做题家没有什么智性，只是狐假虎威，为虎作伥罢了。它需要通过反驳，类似主奴辩证法中的直接的生死斗争，把对象贬低到奴隶的位置上以保持其智力上的主人地位，这是做题家唯一赖以存在的方式——因为他只会做题，无法把他的劳动中介到某个劳动对象中，实现双方平等的相互承认。而无法依靠劳动来确认自身存在的主体，只能依靠不停言说，这是他在符号界中唯一把握自己的存在的方式，而它言说的内容，无非是它倚仗的形式逻辑中的那套命题罢了，那套命题征服了它，它也要反过来用它们征服全世界，它以为那些公理铺设出了全世界，并顺便给予了自我认同的位置。它把自身存在的确定性与形式逻辑的真理性短路了，以为自身存在是一条同样可以从中推导出的定理，而念动那些咒语就能确证自己的存在。",-1),e("p",null,"想想也挺可悲的，虽然大家都是无意识结构的言说主体，但它把自己认同在一条封闭形式系统的真理上，它的存在样态是一条扁平的、抽象的定理，这也是为什么常人会觉得它冰冷，或者 nerd。",-1),e("p",null,"我曾经也这样，活成了一条形式定理+道德禁令（不准说脏话），难怪会有人很讨厌我。",-1),e("p",null,"但是，通过把生命交付给形式系统，它就成为实在论者，而实在论者的生活被一层形式逻辑的罩子保护着，看不见世界的裂隙，只要躲在其中享乐就好了，也挺好的。反正在它们破壳而出之前，先躲的远远的吧，你莫名走进去，人家要么把你当成同样一条定理试图推导/推倒你，要么当成一条反例钉起来，要么觉得你是不可理喻的入侵物（嗯这里居然有人在忤逆形式逻辑基本法？），把你当成异质性清除出去。它主体性里面不服从形式逻辑的剩余被压抑的死死的，那种被压抑的力比多以言说的形式宣泄出来，而言说的内容就是把剩余压在五指山下的“唵嘛呢叭咪吽”。",-1),e("p",null,"写到这里发现把所有实在论者都骂了一遍。emm，有趣。感觉我精神分析神功大成了，hhh。",-1),e("p",null,"骂完了，睡大觉。",-1),e("p",null,"突然发现今天讲的这个案例还有典型的幻听，可能病的真不轻",-1)]))}const _=a(s,[["render",r]]);export{m as __pageData,_ as default};
